import{_ as t,o,c as r,L as n}from"./chunks/framework.bf505f65.js";const g=JSON.parse('{"title":"Hello-AI","description":"","frontmatter":{},"headers":[],"relativePath":"README.md"}'),a={name:"README.md"};function i(s,e,l,c,p,h){return o(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="hello-ai" tabindex="-1">Hello-AI <a class="header-anchor" href="#hello-ai" aria-label="Permalink to &quot;Hello-AI&quot;">​</a></h1><blockquote><p>English | <strong><a href="./README-zh.html">中文文档</a></strong></p></blockquote><p>📚 <strong>Documentation: <a href="https://hello-ai.anzz.top" target="_blank" rel="noreferrer">https://hello-ai.anzz.top</a></strong></p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The initial intention of this project was to help oneself and others connect to the vast world of AI.</p><p>As one of the forerunners in the advent of AI, during the peak popularity of ChatGPT, this initiative provided a series of public AI services to resist being exploited and help some people connect to the world of AI. Time flies, and nowadays, AI is everywhere. The public services offered have stopped, but the original intention of this project remains: <strong>Helping oneself and others connect to the AI world!</strong></p><p>Therefore, this project is undergoing a <strong>V2.0 Refactoring</strong>. We will no longer directly provide fundamental AI services. Instead, we are shifting our focus to the expansive open-source world. This project is now an <strong>Intelligent, Auto-updating AI Project Directory</strong>. Through an AI agent, we will automatically collect, evaluate, categorize, and track the latest and most popular AI extension projects worldwide (covering LLMs, Agents, DevTools, Productivity, etc.).</p><p><strong>Core Features:</strong></p><ul><li>🤖 <strong>AI-Automated Maintenance</strong>: Project collection, tagging, and outdated cleanup are fully driven by cron jobs and LLM scripts, realizing &quot;letting AI help humans connect to AI.&quot;</li><li>📦 <strong>Comprehensive Categorization</strong>: Ensuring you won&#39;t miss out on excellent emerging forces in the open-source AI community.</li><li>🔄 <strong>Continuous Tracking</strong>: Dynamically tracking the latest trends and purging dead projects promptly.</li></ul><p>Welcome to explore and discover the perfect AI tools to boost your efficiency!</p><h2 id="🌟-explore-ai-projects" tabindex="-1">🌟 Explore AI Projects <a class="header-anchor" href="#🌟-explore-ai-projects" aria-label="Permalink to &quot;🌟 Explore AI Projects&quot;">​</a></h2><p>Please use the navigation bar or sidebar of this site to browse this oasis of open-source code meticulously curated for you by our AI agent. Our crawlers and scoring models regularly sweep GitHub for trending projects, keeping this directory fresh!</p><p>📚 <strong>View Online: <a href="https://hello-ai.anzz.top" target="_blank" rel="noreferrer">https://hello-ai.anzz.top</a></strong></p><h2 id="discussion-groups" tabindex="-1">Discussion Groups <a class="header-anchor" href="#discussion-groups" aria-label="Permalink to &quot;Discussion Groups&quot;">​</a></h2><blockquote><p>AI chat groups, some of which offer direct chat experiences with AI, and a platform to exchange ideas with like-minded individuals.</p></blockquote><table><thead><tr><th style="text-align:center;">Join Telegram Group</th><th style="text-align:center;">Join WeChat Group (Note: Join AI group)</th></tr></thead><tbody><tr><td style="text-align:center;"><img src="https://cdn.jsdelivr.net/npm/hello-ai/assets/img/tg_qun.jpg" width="280"></td><td style="text-align:center;"><img src="https://cdn.jsdelivr.net/npm/hello-ai/assets/img/WeChat2.png" width="280"></td></tr></tbody></table><blockquote><p>Please specify your intent to join the WeChat group to avoid unwanted invitations and information harassment.<br> Telegram group link: <a href="https://t.me/auto_gpt_ai" target="_blank" rel="noreferrer">https://t.me/auto_gpt_ai</a><br> TG_bot for conversing with GPT-4: <a href="https://t.me/h5player_bot" target="_blank" rel="noreferrer">https://t.me/h5player_bot</a></p></blockquote><p align="center"><a href="https://trackgit.com"><img src="https://us-central1-trackgit-analytics.cloudfunctions.net/token/ping/lfqoect790vifkbm5n8l" alt="trackgit-views"></a></p>',18)])])}const u=t(a,[["render",i]]);export{g as __pageData,u as default};
